#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<long long> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    for(int i = 1; i < n; i++){
        long long key = nums[i];
        int j = i - 1;
        while(j >= 0 && nums[j] > key){
            nums[j + 1] = nums[j];
            j--;
        }
        nums[j + 1] = key;
    }
    for(int i = 0; i < n; i++){
        cout << nums[i];
        if(i != n - 1) cout << " ";
    }
    cout << endl;
    return 0;
}
